import { z } from "zod";


const registerValidation = z.object({

    body:z.object({

        name:z.string()
            .min(2,"Name must be at least 2 characters"),

        email:z.string()
            .email("Invalid email"),

        password:z.string()
            .min(6,"Password must be at least 6 characters"),

        role:z.enum([
            "TENANT",
            "LANDLORD"
        ]).optional()

    })

});


const loginValidation = z.object({

    body:z.object({

        email:z.string()
            .email("Invalid email"),

        password:z.string()
            .min(1,"Password is required")

    })

});


export const authValidation = {
    registerValidation,
    loginValidation
};